import 'dart:convert';
import 'package:flutter/material.dart';
import 'package:task_manager_flutter/data/models/alert_model.dart';
import 'package:task_manager_flutter/data/utils/api_links.dart';
import 'package:task_manager_flutter/data/models/network_response.dart';
import 'package:task_manager_flutter/data/services/network_caller.dart';
import 'package:task_manager_flutter/data/models/auth_utility.dart';


class BaixaCaller {
  /// ✅ Desfazer baixa de conta (tipo = "pagar" ou "receber")
  static Future<NetworkResponse> desfazerBaixa({
    required String tipo, // "pagar" ou "receber"
    required int id,
  }) async {
    final url = '${ApiLinks.baixas}/desfazer/$tipo/$id';
    return await NetworkCaller().postRequest(url, {});
  }

  /// ✅ Registrar baixa conta a pagar
  static Future<NetworkResponse> registrarBaixaPagar({
    required int id,
    required DateTime dataBaixa,
    required double valorBaixa,
    required int formaPagamentoId,
    required int contaId,
  }) async {
    final url = '${ApiLinks.baixas}/conta-pagar/$id';
    return await NetworkCaller().postRequest(url, {
      'dataBaixa': dataBaixa.toIso8601String(),
      'valorBaixa': valorBaixa,
      'formaPagamentoId': formaPagamentoId,
      'contaId': contaId,
    });
  }

  /// ✅ Registrar baixa conta a receber
  static Future<NetworkResponse> registrarBaixaReceber({
    required int id,
    required DateTime dataBaixa,
    required double valorBaixa,
    required int formaPagamentoId,
    required int contaId,
  }) async {
    final url = '${ApiLinks.baixas}/conta-receber/$id';
    return await NetworkCaller().postRequest(url, {
      'dataBaixa': dataBaixa.toIso8601String(),
      'valorBaixa': valorBaixa,
      'formaPagamentoId': formaPagamentoId,
      'contaId': contaId,
    });
  }
}
